import{_ as a,o as n,c as i,a as e}from"./chunks/framework.8tiMeCK-.js";const k=JSON.parse('{"title":"5.7  使用 Clang 构建内核与模块","description":"","frontmatter":{},"headers":[],"relativePath":"notes/linux_kernel_debugging/ch05_7.md","filePath":"notes/linux_kernel_debugging/ch05_7.md","lastUpdated":null}'),l={name:"notes/linux_kernel_debugging/ch05_7.md"};function p(t,s,r,h,d,o){return n(),i("div",null,[...s[0]||(s[0]=[e(`<h1 id="_5-7-使用-clang-构建内核与模块" tabindex="-1">5.7 使用 Clang 构建内核与模块 <a class="header-anchor" href="#_5-7-使用-clang-构建内核与模块" aria-label="Permalink to &quot;5.7  使用 Clang 构建内核与模块&quot;">​</a></h1><p>现在，让我们进入 Clang 的世界。</p><p>还记得上一节结尾留下的那个悬念吗？有些越界缺陷，比如全局变量的「左越界」（Left-out-of-bounds），只有用 <strong>Clang 11 或更高版本</strong>编译才能被捕获。这不是玄学，是编译器能力的差异。</p><h3 id="为什么要换编译器" tabindex="-1">为什么要换编译器？ <a class="header-anchor" href="#为什么要换编译器" aria-label="Permalink to &quot;为什么要换编译器？&quot;">​</a></h3><p>在动手之前，先说说我们为什么要这么做。</p><p>LLVM 这个项目（全称 Low Level Virtual Machine）名字里虽然带着 &quot;Virtual Machine&quot;，但它现在已经跟传统虚拟机没什么关系了，它是一套非常强大的编译器后端基础设施。而 <strong>Clang</strong>（发音跟 &quot;slang&quot; 押韵），就是基于 LLVM 构建的现代化 C/C++ 编译器前端。</p><p>你可以把 Clang 看作 GCC 的现代替代品。</p><p>但 GCC 老当益壮，为什么要换？原因很硬：</p><ol><li><strong>诊断信息更友好</strong>：Clang 报错比 GCC 清楚得多，这在调试时能救命。</li><li><strong>某些 Bug 它抓得更准</strong>：回到我们刚才说的那个悬念——在上一节我们提到，全局内存上的「左越界」访问，GCC（9.3, 10, 11 版本） reliably 地漏掉了，但 Clang 能抓到。</li></ol><p>这一点至关重要。这意味着要彻底扫除内存盲区，我们手里得有这把新武器。</p><h3 id="别混用编译器-血的教训" tabindex="-1">别混用编译器（血的教训） <a class="header-anchor" href="#别混用编译器-血的教训" aria-label="Permalink to &quot;别混用编译器（血的教训）&quot;">​</a></h3><p>在继续之前，我要先给你打一支预防针。</p><p>我第一次尝试 KASAN 测试失败的时候，百思不得其解，就去请教了 KASAN 的主要维护者之一 <strong>Marco Elver</strong>。他指出了我犯的一个低级错误：<strong>我试图用 Clang 编译内核模块，但目标内核本身却是用 GCC 编译的。</strong></p><p>这是绝对不行的。</p><p>内核和模块必须由同一个编译器构建。为什么？因为底层二进制接口（ABI）必须完全一致。如果编译器不同，结构体对齐、调用约定、甚至函数名修饰都可能对不上。这种不匹配会导致莫名其妙的崩溃，或者——正如我遇到的那样——导致 KASAN 根本无法正常工作。</p><p>所以，规矩只有一条：要么全 GCC，要么全 Clang。既然我们要抓那些难搞的 Bug，那就把内核和模块都用 Clang 11（或者更高版本）重编一遍。</p><h3 id="准备工作-安装-clang" tabindex="-1">准备工作：安装 Clang <a class="header-anchor" href="#准备工作-安装-clang" aria-label="Permalink to &quot;准备工作：安装 Clang&quot;">​</a></h3><p>如果你还在用 Ubuntu 20.04 LTS，你需要手动装一下 Clang 11。</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> apt</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> clang-11</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --install-suggests</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>如果你像我一样，系统里同时躺着 Clang 10 和 Clang 11，为了不搞混，建议手动建一个软链接，把 <code>llvm-objdump</code> 指向版本 11：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ln</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -s</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /usr/bin/llvm-objdump-11</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /usr/bin/llvm-objdump</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><hr><p><strong>「更好的路」——直接上 Ubuntu 21.10</strong></p><p>说实话，在旧系统上手动折腾版本很容易头发掉光。有一个更省心的办法：直接安装 Ubuntu 21.10（或者更高版本）作为一个新的 x86_64 虚拟机。</p><p>Ubuntu 21.10 自带了 Clang 13。我就是这么干的——开了一个新 VM，省去了依赖地狱的痛苦。接下来的步骤，无论你是用 Clang 11 还是 Clang 13，流程都是一样的。</p><h3 id="构建-用-clang-替换-gcc" tabindex="-1">构建：用 Clang 替换 GCC <a class="header-anchor" href="#构建-用-clang-替换-gcc" aria-label="Permalink to &quot;构建：用 Clang 替换 GCC&quot;">​</a></h3><p>好了，工具备好了，现在开始动刀。</p><p>我们要编译那个 5.10.60 的内核。这跟我们在第 1 章里做的事情很像，唯一的区别是在 <code>make</code> 命令里显式指定编译器。</p><p>把终端切到你的内核构建目录，执行：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">$</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> time</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> make</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -j8</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> CC=clang</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">  SYNC</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    include/config/auto.conf.cmd</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">*</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">*</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Restart config...</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">*</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Memory initialization</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">*</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><h3 id="第一次遇到的差异" tabindex="-1">第一次遇到的差异 <a class="header-anchor" href="#第一次遇到的差异" aria-label="Permalink to &quot;第一次遇到的差异&quot;">​</a></h3><p>当你第一次用 <code>CC=clang</code> 跑这个命令时，kbuild 构建系统会检测到环境变了。Clang 支持一些 GCC 没有的高级特性，于是系统会停下来问你一些新配置。</p><p>它首先会问你是否要自动初始化内核栈变量：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Initialize kernel stack variables at function entry</span></span>
<span class="line"><span>&gt; 1. no automatic initialization (weakest) (INIT_STACK_NONE)</span></span>
<span class="line"><span>  2. 0xAA-init everything on the stack (strongest) (INIT_STACK_ALL_PATTERN) (NEW)</span></span>
<span class="line"><span>  3. zero-init everything on the stack (strongest and safest) (INIT_STACK_ALL_ZERO) (NEW)</span></span>
<span class="line"><span>choice[1-3?]:</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>这是一个很诱人的选项——开启它能帮你直接把大量的「未初始化内存读取（UMR）」扼杀在摇篮里。</p><p>但是！</p><p>我们的目标是测试 <strong>KASAN</strong> 和 <strong>UBSAN</strong> 能不能自己抓出这些 Bug。如果编译器一把内存都初始化了，Bug 就被掩盖了。所以，为了验证我们的工具链，我这里故意选默认的 <strong>选项 1</strong>（不自动初始化）。</p><p>接下来，构建过程还会问你一些关于堆内存初始化的问题，比如分配时是否清零、释放时是否清零。这些我都保持默认按了回车（或者选 <code>y</code>，毕竟这不会掩盖 UMR 以外的 Bug）：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Enable heap memory zeroing on allocation by default (INIT_ON_ALLOC_DEFAULT_ON) [Y/n/?] y</span></span>
<span class="line"><span>Enable heap memory zeroing on free by default (INIT_ON_FREE_DEFAULT_ON) [Y/n/?] y</span></span>
<span class="line"><span>*</span></span>
<span class="line"><span>* KASAN: runtime memory debugger</span></span>
<span class="line"><span>*</span></span>
<span class="line"><span>KASAN: runtime memory debugger (KASAN) [Y/n/?] y</span></span>
<span class="line"><span>  KASAN mode</span></span>
<span class="line"><span>  &gt; 1. Generic mode (KASAN_GENERIC)</span></span>
<span class="line"><span>  choice[1]: 1</span></span>
<span class="line"><span> [...]</span></span>
<span class="line"><span>  Back mappings in vmalloc space with real shadow memory (KASAN_VMALLOC) [Y/n/?] y</span></span>
<span class="line"><span>  KUnit-compatible tests of KASAN bug detection capabilities (KASAN_KUNIT_TEST) [M/n/?] m</span></span>
<span class="line"><span>  [...]</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br></div></div><p>一切顺利的话，内核就编译好了。剩下的步骤你应该很熟了——安装模块、安装内核。</p><p><strong>千万别忘了</strong>，命令行里也得带上 <code>CC=clang</code>：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> make</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> CC=clang</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> modules_install</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> &amp;&amp; </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> make</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> CC=clang</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>搞定后，重启你的虚拟机，在 GRUB 菜单里选你新编的这个内核。</p><h3 id="验证-真的是-clang-编的吗" tabindex="-1">验证：真的是 Clang 编的吗？ <a class="header-anchor" href="#验证-真的是-clang-编的吗" aria-label="Permalink to &quot;验证：真的是 Clang 编的吗？&quot;">​</a></h3><p>进系统后，第一件事是确认你没在做梦。跑一下这个：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">$</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> cat</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /proc/version</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">Linux</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> version</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 5.10.60-dbg02</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> (letsdebug@letsdebug-VirtualBox) (</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">Ubuntu</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> clang</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> version</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 13.0.0-2,</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> GNU</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ld</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> (GNU </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">Binutils</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> for</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> Ubuntu</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">) 2.37) </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">#4 SMP PREEMPT Wed ...</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>看括号里的那行字——<code>Ubuntu clang version 13.0.0-2</code>。</p><p>看到这个，说明内核确实是用 Clang 翻译出来的。为了区分，我在用 Clang 编的内核 uname 里加了 <code>-dbg02</code>，而 GCC 编的那版我叫它 <code>5.10.60-dbg02-gcc</code>。这样以后 <code>ls /lib/modules</code> 时就不会搞混了。</p><h3 id="最后一块拼图-编译模块" tabindex="-1">最后一块拼图：编译模块 <a class="header-anchor" href="#最后一块拼图-编译模块" aria-label="Permalink to &quot;最后一块拼图：编译模块&quot;">​</a></h3><p>内核准备好了，现在轮到我们的测试模块 <code>test_kmembugs</code>。</p><p>切到源码目录，把 <code>CC</code> 变量传递给 make：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">book_sr</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">c</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/ch5/kmembugs_test</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">make</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> CC=clang</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>很简单，对吧？</p><p>其实我为了省事，已经把这个逻辑写进了 <code>load_testmod</code> 脚本里——它会自动检测当前内核是用哪个编译器编的，然后用对应的编译器去构建模块。这样我就不用每次手动指定了。</p><p><strong>动手时间</strong></p><blockquote><p>俗话说得好，纸上得来终觉浅。</p><p>现在轮到你了：</p><p><strong>练习</strong>：从零开始，用 Clang 构建一个调试内核，并用它来编译我们的 <code>test_kmembugs.ko</code> 模块。跑一遍之前的那些测试用例，特别是那个曾经被 GCC 漏掉的「左越界」Bug，看看 Clang 是怎么把它揪出来的。</p></blockquote><p>到这里，我们关于内核内存缺陷检测的第一部分深度之旅就告一段落了。</p><p>手里有了 KASAN、UBSAN，还有了 Clang 这把利剑，我们现在的武器库已经相当完备了。接下来，我们要做个复盘——把所有用过的工具和技术放在一起，仔细比对一下它们的优劣，看看在什么场景下该用什么招。</p><p>这就到了下一节：「Catching memory defects in the kernel – comparisons and notes (Part 1)」。那有一张大表等着你。</p>`,59)])])}const g=a(l,[["render",p]]);export{k as __pageData,g as default};
